#include <stdio.h>

void reverseArray(int *arr, int size){
    int *l = arr;
    int *r = arr + size - 1;
    while(l < r){
        int tmp = *l;
        *l = *r;
        *r = tmp;
        l++; r--;
    }
}

int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n;
        scanf("%d", &n);
        int arr[1000];
        for(int i=0;i<n;i++) scanf("%d", &arr[i]);
        reverseArray(arr, n);
        for(int i=0;i<n;i++){
            printf("%d", arr[i]);
            if(i+1<n) printf(" ");
        }
        if(T) printf("\n");
    }
    return 0;
}

